import SideCart from '@/components/SideCart.vue'

export default {
  name: 'App',
  components: {
    SideCart
  },
  data () {
    return {
      searchShow: false,
      sidenavShow: false,
      saleShow: false,
      topShow: false,
      bottomShow: false,
      onePieceShow: false,
      homeWearShow: false,
      accessoryShow: false,
      cartShow: false,
      inventory: {
        id: 0,
        color: '',
        size: '',
        qty: 0
      },
      cart: [],
      total: 0
    }
  },
  computed: {
    totalQuantity () {
      return this.total
    }
  }
}
